function calculerPrixFinal(prixInitial: number, remise?: number, taxe: number = 19): number {
  const prixApresRemise = remise ? prixInitial * (1 - remise / 100) : prixInitial;
  const prixFinal = prixApresRemise * (1 + taxe / 100);
  return prixFinal;
}
