type Operation = 'moyenne' | 'max' | 'min';

function analyserTempsLivraison(
  ...temps: number[]
): (seuil?: number, operation?: Operation) => { resultat: number; nbCommandes: number } {
  return (seuil: number = 48, operation: Operation = 'moyenne') => {
    const tempsFiltres = temps.filter(t => t <= seuil);
    const nb = tempsFiltres.length;
    if (nb === 0) return { resultat: 0, nbCommandes: 0 };

    let resultat: number;
    switch (operation) {
      case 'moyenne':
        resultat = tempsFiltres.reduce((a, b) => a + b, 0) / nb;
        break;
      case 'max':
        resultat = Math.max(...tempsFiltres);
        break;
      case 'min':
        resultat = Math.min(...tempsFiltres);
        break;
      default:
        throw new Error(`Opération ${operation} non supportée`);
    }
    return { resultat, nbCommandes: nb };
  };
}

// Exemple d’utilisation :
const analyse = analyserTempsLivraison(12, 48, 72, 36, 55);
console.log(analyse(50, 'max')); // { resultat: 48, nbCommandes: 3 }
```
